+/// <summary>
+/// Clears Shopify identifiers from documents copied from posted invoices.
+/// </summary>
+codeunit 30500 "Shpfy Copy Document"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesDocument', '', false, false)]
+    local procedure ClearShpfyIdentifiersAfterCopy(FromDocumentType: Option; FromDocumentNo: Code[20]; var ToSalesHeader: Record "Sales Header";
+        FromDocOccurenceNo: Integer; FromDocVersionNo: Integer; IncludeHeader: Boolean; RecalculateLines: Boolean; MoveNegLines: Boolean)
+    var
+        FromDocTypeEnum: Enum "Sales Document Type From";
+    begin
+        FromDocTypeEnum := FromDocTypeEnum.FromInteger(FromDocumentType.AsInteger());
+        if FromDocTypeEnum <> FromDocTypeEnum::"Posted Invoice" then
+            exit;
+
+        if ToSalesHeader."Document Type" <> ToSalesHeader."Document Type"::Invoice then
+            exit;
+
+        if not IncludeHeader then
+            exit;
+
+        if (ToSalesHeader."Shpfy Order Id" = 0) and (ToSalesHeader."Shpfy Order No." = '') then
+            exit;
+
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+        ToSalesHeader.Modify(true);
+    end;
+}

